resource "azurerm_storage_account" "edu" {
  name                     = "edustorage"
  resource_group_name      = "compliance-rg"
  account_tier             = "Premium"
  enable_https_traffic_only = true
  tags = { vertical = "education" }
}

def guardrail_check(prompt):
    flagged = compliance_llm(prompt)
    if flagged:
        return "Request blocked: policy violation"
    return downstream_llm(prompt)

resource "azuread_conditional_access_policy" "biometric_mfa" {
  display_name = "Require biometric or MFA for admin access"
  conditions {
    users {
      include_roles = ["Global Administrator"]
    }
  }
  grant_controls {
    built_in_controls = ["mfa"]
  }
}
